import{_ as t,o as a,c as n,a7 as o}from"./chunks/framework.Doa-uGBm.js";const f=JSON.parse('{"title":"Untitled boolean in Mermaid Config Schema","description":"","frontmatter":{"editLink":"https://github.com/mermaid-js/mermaid/edit/develop/packages/mermaid/src/schemas/config.schema.yaml","head":[["link",{"rel":"canonical","href":"https://mermaid.ai/open-source/config/schema-docs/config-properties-elk-properties-keepentrynodeontop.html"}]]},"headers":[],"relativePath":"config/schema-docs/config-properties-elk-properties-keepentrynodeontop.md","filePath":"config/schema-docs/config-properties-elk-properties-keepentrynodeontop.md"}'),i={name:"config/schema-docs/config-properties-elk-properties-keepentrynodeontop.md"};function s(l,e,d,r,p,c){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="untitled-boolean-in-mermaid-config-schema" tabindex="-1">Untitled boolean in Mermaid Config Schema <a class="header-anchor" href="#untitled-boolean-in-mermaid-config-schema" aria-label="Permalink to &quot;Untitled boolean in Mermaid Config Schema&quot;">​</a></h1><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://mermaid.js.org/schemas/config.schema.json#/properties/elk/properties/keepEntryNodeOnTop</span></span></code></pre></div><p>Elk specific option that keeps the entry node of a recursive flow at the top of the layout.</p><p>When a flow loops back on itself (a back-edge to an earlier node), ELK&#39;s degree-based cycle-breaking has no notion of an &quot;entry point&quot; and may rank the first-declared node in the middle, scrambling the reading order. When enabled, the entry node of each cyclic component is pinned to the first layer so the diagram still reads from its entry. Acyclic flows always have a natural source, so this has no effect on them.</p><p>Only applies when the cyclic flow has no node without incoming edges: if the loop is fed from outside (e.g. a start node pointing into it), that component already has a natural source and nothing is pinned. Detection is also scoped per container, so cycles that cross a subgraph boundary are not detected.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Abstract</th><th style="text-align:left;">Extensible</th><th style="text-align:left;">Status</th><th style="text-align:left;">Identifiable</th><th style="text-align:left;">Custom Properties</th><th style="text-align:left;">Additional Properties</th><th style="text-align:left;">Access Restrictions</th><th style="text-align:left;">Defined In</th></tr></thead><tbody><tr><td style="text-align:left;">Can be instantiated</td><td style="text-align:left;">No</td><td style="text-align:left;">Unknown status</td><td style="text-align:left;">Unknown identifiability</td><td style="text-align:left;">Forbidden</td><td style="text-align:left;">Allowed</td><td style="text-align:left;">none</td><td style="text-align:left;"><a href="/dochub/mermaid/schemas/config.schema.json" title="open original schema">config.schema.json*</a></td></tr></tbody></table><h2 id="keepentrynodeontop-type" tabindex="-1">keepEntryNodeOnTop Type <a class="header-anchor" href="#keepentrynodeontop-type" aria-label="Permalink to &quot;keepEntryNodeOnTop Type&quot;">​</a></h2><p><code>boolean</code></p><h2 id="keepentrynodeontop-default-value" tabindex="-1">keepEntryNodeOnTop Default Value <a class="header-anchor" href="#keepentrynodeontop-default-value" aria-label="Permalink to &quot;keepEntryNodeOnTop Default Value&quot;">​</a></h2><p>The default value is:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div>',11)])])}const m=t(i,[["render",s]]);export{f as __pageData,m as default};
